// Input validation helpers
function validateIdentifier(name, type = 'identifier') {
  if (typeof name !== 'string' || !/^[a-z_][a-z0-9_]*$/.test(name)) {
    throw new ValidationError(`Invalid ${type}: ${name}`);
  }
  return name;
}

function validateTableName(table) {
  validateIdentifier(table, 'table name');
  if (!ALLOWED_TABLES.has(table)) {
    throw new ValidationError(`Table not allowed: ${table}`);
  }
  return table;
}

function validateColumns(table, columns) {
  const allowedCols = ALLOWED_COLUMNS[table];
  if (!allowedCols) {
    throw new ValidationError(`No column definitions for table: ${table}`);
  }
  for (const col of columns) {
    validateIdentifier(col, 'column name');
    if (!allowedCols.has(col)) {
      throw new ValidationError(`Column '${col}' not allowed for table '${table}'`);
    }
  }
  return columns;
}

function sanitizeValue(value) {
  if (value === null || value === undefined) return null;
  if (typeof value === 'number' || typeof value === 'boolean') return value;
  if (typeof value === 'string') {
    if (value.length > 10000) {
      throw new ValidationError('Value exceeds maximum length');
    }
    return value;
  }
  if (typeof value === 'object') {
    return JSON.stringify(value);
  }
  return String(value);
}

// Custom error classes
class ValidationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'ValidationError';
  }
}

class ProcessingError extends Error {
  constructor(message, retryable = true) {
    super(message);
    this.name = 'ProcessingError';
    this.retryable = retryable;
  }
}

// Message handler registry
class MessageHandlerRegistry extends EventEmitter {
  constructor() {
    super();
    this.handlers = new Map();
  }

  register(messageType, handler) {
    if (!ALLOWED_MESSAGE_TYPES.has(messageType)) {
      throw new Error(`Cannot register handler for unknown message type: ${messageType}`);
    }
    this.handlers.set(messageType, handler);
    logger.info(`Registered handler for message type: ${messageType}`);
  }

  getHandler(messageType) {
    return this.handlers.get(messageType);
  }

  hasHandler(messageType) {
    return this.handlers.has(messageType);
  }
}

// Query builder using parameterized queries only
class SafeQueryBuilder {
  static buildInsert(table, data) {
    validateTableName(table);
    const columns = Object.keys(data);
    validateColumns(table, columns);
    const values = columns.map((col) => sanitizeValue(data[col]));

    const placeholders = columns.map((_, i) => `$${i + 1}`).join(', ');
    const quotedColumns = columns.map((col) => `"${col}"`).join(', ');
    const query = `INSERT INTO "${table}" (${quotedColumns}) VALUES (${placeholders}) RETURNING *`;

    return { query, values };
  }

  static buildUpdate(table, data, conditions) {
    validateTableName(table);
    const setCols = Object.keys(data);
    const condCols = Object.keys(conditions);
    validateColumns(table, [...setCols, ...condCols]);

    let paramIndex = 1;
    const setClause = setCols.map((col) => `"${col}" = $${paramIndex++}`).join(', ');
    const whereClause = condCols.map((col) => `"${col}" = $${paramIndex++}`).join(' AND ');

    const values = [
      ...setCols.map((col) => sanitizeValue(data[col])),
      ...condCols.map((col) => sanitizeValue(conditions[col])),
    ];

    const query = `UPDATE "${table}" SET ${setClause} WHERE ${whereClause} RETURNING *`;

    return { query, values };
  }

  static buildDelete(table, conditions) {
    validateTableName(table);
    const condCols = Object.keys(conditions);
    validateColumns(table, condCols);

    let paramIndex = 1;
    const whereClause = condCols.map((col) => `"${col}" = $${paramIndex++}`).join(' AND ');
    const values = condCols.map((col) => sanitizeValue(conditions[col]));

    const query = `DELETE FROM "${table}" WHERE ${whereClause} RETURNING *`;

    return { query, values };
  }

  static buildSelect(table, conditions, columns = ['*']) {
    validateTableName(table);
    const condCols = Object.keys(conditions);
    validateColumns(table, condCols);
    if (columns[0] !== '*') {
      validateColumns(table, columns);
    }

    let paramIndex = 1;
    const selectCols = columns[0] === '*' ? '*' : columns.map((col) => `"${col}"`).join(', ');
    const whereClause = condCols.map((col) => `"${col}" = $${paramIndex++}`).join(' AND ');
    const values = condCols.map((col) => sanitizeValue(conditions[col]));

    const query = `SELECT ${selectCols} FROM "${table}" WHERE ${whereClause}`;

    return { query, values };
  }
}

// Database executor
class DatabaseExecutor {
  static async execute(queryObj) {
    const client = await pool.connect();
    try {
      const result = await client.query(queryObj.query, queryObj.values);
      return result;
    } finally {
      client.release();
    }
  }

  static async executeInTransaction(queries) {
    const client = await pool.connect();
    try {
      await client.query('BEGIN');
      const results = [];
      for (const queryObj of queries) {
        const result = await client.query(queryObj.query, queryObj.values);
        results.push(result);
      }
      await client.query('COMMIT');
      return results;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }
}

