// Message processor
class MessageProcessor {
  constructor(registry) {
    this.registry = registry;
    this.processedCount = 0;
    this.errorCount = 0;
  }

  async process(rawMessage) {
    const startTime = Date.now();
    let message;

    // Parse JSON
    try {
      const content = rawMessage.content.toString('utf-8');
      if (content.length > 1024 * 1024) {
        throw new ValidationError('Message exceeds maximum size of 1MB');
      }
      message = JSON.parse(content);
    } catch (error) {
      if (error instanceof ValidationError) {
        throw error;
      }
      throw new ValidationError(`Invalid JSON message: ${error.message}`);
    }

    // Validate structure
    validateMessageStructure(message);

    const messageId = message.id || rawMessage.properties.messageId || uuidv4();
    const messageType = message.type;
    const payload = message.payload;

    logger.info('Processing message', {
      messageId,
      messageType,
      correlationId: message.correlationId || rawMessage.properties.correlationId,
    });

    // Get handler
    const handler = this.registry.getHandler(messageType);
    if (!handler) {
      throw new ValidationError(`No handler registered for message type: ${messageType}`);
    }

    // Execute handler
    try {
      const result = await handler(payload);
      const duration = Date.now() - startTime;
      this.processedCount++;

      logger.info('Message processed successfully', {
        messageId,
        messageType,
        durationMs: duration,
        totalProcessed: this.processedCount,
      });

      this.registry.emit('message.processed', { messageId, messageType, duration, result });
      return result;
    } catch (error) {
      const duration = Date.now() - startTime;
      this.errorCount++;

      logger.error('Message processing failed', {
        messageId,
        messageType,
        error: error.message,
        errorType: error.name,
        durationMs: duration,
        totalErrors: this.errorCount,
      });

      this.registry.emit('message.failed', { messageId, messageType, error, duration });
      throw error;
    }
  }
}

// RabbitMQ consumer
class RabbitMQConsumer {
  constructor(processor) {
    this.processor = processor;
    this.connection = null;
    this.channel = null;
    this.isShuttingDown = false;
    this.retryCount = 0;
    this.maxRetries = 10;
  }

  async connect() {
    try {
      logger.info('Connecting to RabbitMQ', { url: config.rabbitmq.url.replace(/\/\/.*@/, '//***@') });

      this.connection = await amqp.connect(config.rabbitmq.url);

      this.connection.on('error', (err) => {
        logger.error('RabbitMQ connection error', { error: err.message });
      });

      this.connection.on('close', () => {
        if (!this.isShuttingDown) {
          logger.warn('RabbitMQ connection closed, attempting reconnect');
          this.reconnect();
        }
      });

      this.channel = await this.connection.createChannel();

      this.channel.on('error', (err) => {
        logger.error('RabbitMQ channel error', { error: err.message });
      });

      this.channel.on('close', () => {
        if (!this.isShuttingDown) {
          logger.warn('RabbitMQ channel closed');
        }
      });

      // Set prefetch
      await this.channel.prefetch(config.rabbitmq.prefetch);

      // Assert dead letter exchange and queue
      await this.channel.assertExchange(`${config.rabbitmq.exchange}.dlx`, 'direct', { durable: true });
      await this.channel.assertQueue(config.rabbitmq.deadLetterQueue, {
        durable: true,
        arguments: {
          'x-message-ttl': 86400000, // 24 hours
        },
      });
      await this.channel.bindQueue(
        config.rabbitmq.deadLetterQueue,
        `${config.rabbitmq.exchange}.dlx`,
        config.rabbitmq.queue
      );

      // Assert main exchange and queue
      await this.channel.assertExchange(config.rabbitmq.exchange, 'topic', { durable: true });
      await this.channel.assertQueue(config.rabbitmq.queue, {
        durable: true,
        arguments: {
          'x-dead-letter-exchange': `${config.rabbitmq.exchange}.dlx`,
          'x-dead-letter-routing-key': config.rabbitmq.queue,
        },
      });

      // Bind queue to exchange for all allowed message types
      for (const messageType of ALLOWED_MESSAGE_TYPES) {
        await this.channel.bindQueue(config.rabbitmq.queue, config.rabbitmq.exchange, messageType);
      }

      this.retryCount = 0;
      logger.info('Connected to RabbitMQ successfully');
    } catch (error) {
      logger.error('Failed to connect to RabbitMQ', { error: error.message });
      throw error;
    }
  }

  async reconnect() {
    if (this.isShuttingDown) return;

    this.retryCount++;
    if (this.retryCount > this.maxRetries) {
      logger.error('Max reconnection attempts reached, exiting');
      process.exit(1);
    }

    const delay = Math.min(
      config.rabbitmq.reconnectDelay * Math.pow(2, this.retryCount - 1),
      30000
    );

    logger.info(`Reconnecting in ${delay}ms (attempt ${this.retryCount}/${this.maxRetries})`);

    setTimeout(async () => {
      try {
        await this.connect();
        await this.startConsuming();
      } catch (error) {
        logger.error('Reconnection failed', { error: error.message });
        this.reconnect();
      }
    }, delay);
  }

  async startConsuming() {
    if (!this.channel) {
      throw new Error('Channel not initialized');
    }

    logger.info('Starting to consume messages', { queue: config.rabbitmq.queue });

    await this.channel.consume(config.rabbitmq.queue, async (msg) => {
      if (!msg) return;

      const retryCount = (msg.properties.headers && msg.properties.headers['x-retry-count']) || 0;
      const maxMessageRetries = 3;

      try {
        await this.processor.process(msg);
        this.channel.ack(msg);
      } catch (error) {
        if (error instanceof ValidationError) {
          // Non-retryable: send to DLQ
          logger.error('Validation error, sending to DLQ', {
            error: error.message,
            messageId: msg.properties.messageId,
          });
          this.channel.nack(msg, false, false);
        } else if (error instanceof ProcessingError && !error.retryable) {
          // Non-retryable processing error: send to DLQ
          logger.error('Non-retryable processing error, sending to DLQ', {
            error: error.message,
            messageId: msg.properties.messageId,
          });
          this.channel.nack(msg, false, false);
        } else if (retryCount >= maxMessageRetries) {
          // Max retries exceeded: send to DLQ
          logger.error('Max retries exceeded, sending to DLQ', {
            error: error.message,
            retryCount,
            messageId: msg.properties.messageId,
          });
          this.channel.nack(msg, false, false);
        } else {
          // Retryable: republish with incremented retry count
          logger.warn('Retryable error, requeueing', {
            error: error.message,
            retryCount: retryCount + 1,
            messageId: msg.properties.messageId,
          });

          try {
            const headers = { ...msg.properties.headers, 'x-retry-count': retryCount + 1 };
            this.channel.publish(
              config.rabbitmq.exchange,
              msg.fields.routingKey,
              msg.content,
              {
                ...msg.properties,
                headers,
                persistent: true,
              }
            );
            this.channel.ack(msg);
          } catch (publishError) {
            logger.error('Failed to republish message', { error: publishError.message });
            this.channel.nack(msg, false, true);
          }
        }
      }
    }, {
      noAck: false,
      consumerTag: `consumer-${process.pid}-${uuidv4().slice(0, 8)}`,
    });

    logger.info('Consumer started successfully');
  }

  async shutdown() {
    this.isShuttingDown = true;
    logger.info('Shutting down RabbitMQ consumer');

    try {
      if (this.channel) {
        await this.channel.close();
      }
      if (this.connection) {
        await this.connection.close();
      }
      logger.info('RabbitMQ consumer shut down successfully');
    } catch (error) {
      logger.error('Error during shutdown', { error: error.message });
    }
  }
}

// Health check server
const http = require('http');

function createHealthServer(consumer, processor) {
  const server = http.createServer((req, res) => {
    if (req.url === '/health' && req.method === 'GET') {
      const isHealthy = consumer.connection && consumer.channel && !consumer.isShuttingDown;
      const status = isHealthy ? 200 : 503;
      res.writeHead(status, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({
        status: isHealthy ? 'healthy' : 'unhealthy',
        uptime: process.uptime(),
        processedCount: processor.processedCount,
        errorCount: processor.errorCount,
        timestamp: new Date().toISOString(),
      }));
    } else if (req.url === '/ready' && req.method === 'GET') {
      const isReady = consumer.connection && consumer.channel;
      res.writeHead(isReady ? 200 : 503, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ ready: !!isReady }));
    } else {
      res.writeHead(404);
      res.end();
    }
  });

  return server;
}

// Main startup
async function main() {
  logger.info('Starting microservice');

  // Initialize registry and register handlers
  const registry = new MessageHandlerRegistry();
  registerHandlers(registry);

  // Initialize processor
  const processor = new MessageProcessor(registry);

  // Initialize consumer
  const consumer = new RabbitMQConsumer(processor);

  // Health check server
  const healthServer = createHealthServer(consumer, processor);
  const healthPort = parseInt(process.env.HEALTH_PORT || '3000', 10);
  healthServer.listen(healthPort, () => {
    logger.info(`Health check server listening on port ${healthPort}`);
  });

  // Connect and start consuming
  try {
    await consumer.connect();
    await consumer.startConsuming();
    logger.info('Microservice started successfully');
  } catch (error) {
    logger.error('Failed to start microservice', { error: error.message });
    consumer.reconnect();
  }

  // Graceful shutdown
  const shutdown = async (signal) => {
    logger.info(`Received ${signal}, starting graceful shutdown`);

    // Stop accepting new health checks
    healthServer.close();

    // Shutdown consumer
    await consumer.shutdown();

    // Close database pool
    await pool.end();
    logger.info('Database pool closed');

    process.exit(0);
  };

  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));

  process.on('uncaughtException', (error) => {
    logger.error('Uncaught exception', { error: error.message, stack: error.stack });
    shutdown('uncaughtException');
  });

  process.on('unhandledRejection', (reason) => {
    logger.error('Unhandled rejection', { reason: String(reason) });
  });
}

main().catch((error) => {
  logger.error('Fatal error during startup', { error: error.message });
  process.exit(1);
});

module.exports = {
  MessageHandlerRegistry,
  MessageProcessor,
  SafeQueryBuilder,
  DatabaseExecutor,
  RabbitMQConsumer,
  ValidationError,
  ProcessingError,
  validateMessageStructure,
  ALLOWED_MESSAGE_TYPES,
  ALLOWED_TABLES,
  ALLOWED_COLUMNS,
};